            alpha: [90, 0, 90, -90, 90, 0]    // alpha in degrees
        };

        const SCALE = 0.01; // Convert mm to scene units

        let scene, camera, renderer, robot;
        let joints = { q1: 0, q2: 0, q3: 0, q4: 0, q5: 0, q6: 0 };
