            const forwardSprite = createTextSprite('Forward (X+)', 0xffaa00);
            forwardSprite.position.set(3.5, 0.3, 0);
            scene.add(forwardSprite);

            // Build robot
            buildRobot();

            // Orbit controls (simple implementation)
            setupControls();

            // Event listeners
