            robot = new THREE.Group();

            // Get scaled DH params
            const d = dhParams.d.map(v => v * SCALE);
            const a = dhParams.a.map(v => v * SCALE);
            const alpha = dhParams.alpha.map(v => v * Math.PI / 180);
            const thetaOffset = dhParams.theta.map(v => v * Math.PI / 180);

            // Materials
            const baseMat = new THREE.MeshStandardMaterial({ color: 0x4a5568, metalness: 0.7, roughness: 0.3 });
            const linkMat = new THREE.MeshStandardMaterial({ color: 0x718096, metalness: 0.6, roughness: 0.4 });
            const jointMat = new THREE.MeshStandardMaterial({ color: 0x2d3748, metalness: 0.8, roughness: 0.2 });
