            transform5.position.y = d[4];
            transform5.position.z = 0.3;
            transform5.rotation.x = alpha[4]; // 90 degrees
            link5.add(transform5);

            // Joint 6 group
            const joint6 = new THREE.Group();
            transform5.add(joint6);

            // Link 6 visual - tool flange
            const link6 = new THREE.Group();
            const flange = new THREE.CylinderGeometry(0.22, 0.22, 0.1, 32);
            const flangeMesh = new THREE.Mesh(flange, jointMat);
            flangeMesh.rotation.x = Math.PI/2;
            flangeMesh.position.z = 0.05;
            link6.add(flangeMesh);

            // Tool/gripper indicator
            const toolLength = Math.max(0.2, d[5] * 0.5);
            const tool = new THREE.ConeGeometry(0.15, toolLength, 16);
            const toolMeshObj = new THREE.Mesh(tool, toolMat);
            toolMeshObj.rotation.x = Math.PI/2;
            toolMeshObj.position.z = 0.1 + toolLength/2;
            link6.add(toolMeshObj);

            joint6.add(link6);
            createCoordinateFrame(link6, 0.5, 'Frame 6 (Tool)', new THREE.Vector3(0, 0, 0.1 + toolLength));

            // Store joint references and theta offsets
            robot.joints = {
                j1: joint1,
                j2: joint2,
                j3: joint3,
                j4: joint4,
                j5: joint5,
                j6: joint6
            };
            robot.thetaOffset = thetaOffset;

            scene.add(robot);

            // Apply current joint angles
            updateRobot();

            // Update frame visibility based on checkbox
            const showFrames = document.getElementById('showFrames').checked;
            const showLabels = document.getElementById('showLabels').checked;
            coordinateFrames.forEach(f => f.visible = showFrames);
            frameLabels.forEach(l => l.visible = showLabels);
        }

        function createCoordinateFrame(parent, size, label, offset = new THREE.Vector3(0, 0, 0)) {
            const frame = new THREE.Group();
            frame.position.copy(offset);

            // X axis (red)
            const xArrow = new THREE.ArrowHelper(
                new THREE.Vector3(1, 0, 0),
                new THREE.Vector3(0, 0, 0),
                size,
                0xff4444,
                size * 0.15,
                size * 0.08
            );
            frame.add(xArrow);

            // Y axis (green)
            const yArrow = new THREE.ArrowHelper(
                new THREE.Vector3(0, 1, 0),
                new THREE.Vector3(0, 0, 0),
                size,
                0x44ff44,
                size * 0.15,
                size * 0.08
            );
            frame.add(yArrow);

            // Z axis (blue)
            const zArrow = new THREE.ArrowHelper(
                new THREE.Vector3(0, 0, 1),
                new THREE.Vector3(0, 0, 0),
                size,
                0x4444ff,
                size * 0.15,
                size * 0.08
            );
            frame.add(zArrow);

            parent.add(frame);
            coordinateFrames.push(frame);

            // Label
            if (label) {
                const sprite = createTextSprite(label, 0xffffff);
                sprite.position.set(size * 0.3, size * 0.8, size * 0.3);
                frame.add(sprite);
                frameLabels.push(sprite);
            }

            return frame;
        }

        function createTextSprite(text, color) {
            const canvas = document.createElement('canvas');
            const context = canvas.getContext('2d');
            canvas.width = 256;
            canvas.height = 64;

            context.font = 'Bold 24px Arial';
            context.fillStyle = '#' + color.toString(16).padStart(6, '0');
            context.textAlign = 'center';
            context.fillText(text, 128, 40);

            const texture = new THREE.CanvasTexture(canvas);
            const material = new THREE.SpriteMaterial({ map: texture, transparent: true });
            const sprite = new THREE.Sprite(material);
            sprite.scale.set(1.5, 0.4, 1);

            return sprite;
        }

        function updateRobot() {
            if (!robot || !robot.joints) return;

            const deg2rad = Math.PI / 180;
            const offset = robot.thetaOffset;

            // Apply joint angles with theta offsets
            robot.joints.j1.rotation.y = joints.q1 * deg2rad + offset[0];
            robot.joints.j2.rotation.y = joints.q2 * deg2rad + offset[1];
            robot.joints.j3.rotation.y = joints.q3 * deg2rad + offset[2];
            robot.joints.j4.rotation.y = joints.q4 * deg2rad + offset[3];
            robot.joints.j5.rotation.y = joints.q5 * deg2rad + offset[4];
            robot.joints.j6.rotation.y = joints.q6 * deg2rad + offset[5];
        }

        function setupEventListeners() {
            ['q1', 'q2', 'q3', 'q4', 'q5', 'q6'].forEach(id => {
                const slider = document.getElementById(id);
                slider.addEventListener('input', (e) => {
                    joints[id] = parseFloat(e.target.value);
                    document.getElementById(id + '-val').textContent = e.target.value + '°';
                    updateRobot();
                });
            });

            document.getElementById('showFrames').addEventListener('change', (e) => {
                coordinateFrames.forEach(f => f.visible = e.target.checked);
            });

            document.getElementById('showLabels').addEventListener('change', (e) => {
                frameLabels.forEach(l => l.visible = e.target.checked);
            });
        }

        function setupControls() {
            let isDragging = false;
            let isPanning = false;
            let previousMouse = { x: 0, y: 0 };
            let spherical = { theta: Math.PI/4, phi: Math.PI/3, radius: 14 };

            const container = renderer.domElement;

            container.addEventListener('mousedown', (e) => {
                if (e.button === 0) isDragging = true;
                if (e.button === 2) isPanning = true;
                previousMouse = { x: e.clientX, y: e.clientY };
            });

            container.addEventListener('mouseup', () => {
                isDragging = false;
                isPanning = false;
            });

            container.addEventListener('mousemove', (e) => {
                if (!isDragging && !isPanning) return;

                const deltaX = e.clientX - previousMouse.x;
                const deltaY = e.clientY - previousMouse.y;

                if (isDragging) {
                    spherical.theta -= deltaX * 0.01;
                    spherical.phi = Math.max(0.1, Math.min(Math.PI - 0.1, spherical.phi - deltaY * 0.01));
                }

                if (isPanning) {
                    const panSpeed = 0.02;
                    camera.position.x -= deltaX * panSpeed;
                    camera.position.y += deltaY * panSpeed;
                }

                previousMouse = { x: e.clientX, y: e.clientY };
                updateCamera();
            });

            container.addEventListener('wheel', (e) => {
                spherical.radius = Math.max(5, Math.min(30, spherical.radius + e.deltaY * 0.01));
                updateCamera();
            });

            container.addEventListener('contextmenu', (e) => e.preventDefault());

            function updateCamera() {
                camera.position.x = spherical.radius * Math.sin(spherical.phi) * Math.cos(spherical.theta);
                camera.position.y = spherical.radius * Math.cos(spherical.phi);
                camera.position.z = spherical.radius * Math.sin(spherical.phi) * Math.sin(spherical.theta);
                camera.lookAt(0, 2, 0);
            }

            updateCamera();
        }

        function resetJoints() {
            ['q1', 'q2', 'q3', 'q4', 'q5', 'q6'].forEach(id => {
                joints[id] = 0;
                document.getElementById(id).value = 0;
                document.getElementById(id + '-val').textContent = '0°';
            });
            updateRobot();
        }

        function demoPosition() {
            const demo = { q1: 30, q2: 45, q3: -30, q4: 90, q5: -45, q6: 0 };
            Object.keys(demo).forEach(id => {
                joints[id] = demo[id];
                document.getElementById(id).value = demo[id];
                document.getElementById(id + '-val').textContent = demo[id] + '°';
            });
            updateRobot();
        }

        function applyDHParams() {
            // Read all DH parameters from inputs
            for (let i = 1; i <= 6; i++) {
                dhParams.theta[i-1] = parseFloat(document.getElementById(`dh-theta${i}`).value) || 0;
                dhParams.d[i-1] = parseFloat(document.getElementById(`dh-d${i}`).value) || 0;
                dhParams.a[i-1] = parseFloat(document.getElementById(`dh-a${i}`).value) || 0;
                dhParams.alpha[i-1] = parseFloat(document.getElementById(`dh-alpha${i}`).value) || 0;
            }

            // Rebuild the robot with new parameters
            buildRobot();
        }

        function resetDHParams() {
            // Reset to Thor robot values
            const defaults = {
                theta: [0, -90, 0, 0, 0, 0],
                d: [202, 0, 0, 195, 0, 67.15],
                a: [0, 160, 0, 0, 0, 0],
                alpha: [90, 0, 90, -90, 90, 0]
            };

            dhParams = JSON.parse(JSON.stringify(defaults));

            // Update input fields
            for (let i = 1; i <= 6; i++) {
                document.getElementById(`dh-theta${i}`).value = defaults.theta[i-1];
                document.getElementById(`dh-d${i}`).value = defaults.d[i-1];
                document.getElementById(`dh-a${i}`).value = defaults.a[i-1];
                document.getElementById(`dh-alpha${i}`).value = defaults.alpha[i-1];
            }

            buildRobot();
        }

        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        function animate() {
            requestAnimationFrame(animate);
            renderer.render(scene, camera);
        }
    </script>
